SELECT r.*, m.nickname FROM recipe r
JOIN member m ON r.member_id = m.member_id
WHERE recipe_id = #{num}

SELECT COUNT(*) FROM recipe r JOIN category c ON r.category_id = c.category_id
(c.category_name = #{category} OR c.sub_category_name = #{category})
AND CAST(REPLACE(r.cooking_time, '분', '') AS UNSIGNED) <= #{maxCookTime}

SELECT r.* FROM recipe r
JOIN food f ON r.food_id = f.food_id
JOIN category c ON f.category_id = c.category_id


        c.category_name = #{category}


        AND CAST(REPLACE(r.cooking_time, '분', '') AS UNSIGNED) <= #{maxCookTime}




        ORDER BY CAST(REPLACE(r.cooking_time, '분', '') AS UNSIGNED) ASC


        ORDER BY r.created_date DESC


LIMIT 9 OFFSET #{offset}
